import React, { useEffect, useMemo, useState } from "react";
import axios from "axios";
import { Link, useLocation } from "react-router-dom";
import BusCard from "../components/BusCard";
import { Bus } from "../types";

const API_BASE = "http://localhost:5000/api";

const BusList: React.FC = () => {
  const [buses, setBuses] = useState<Bus[]>([]);
  const [loading, setLoading] = useState(true);
  const location = useLocation();

  const searchInfo = useMemo(() => {
    const params = new URLSearchParams(location.search);
    return {
      departureCity: params.get("departureCity") || "",
      arrivalCity: params.get("arrivalCity") || "",
      date: params.get("date") || ""
    };
  }, [location.search]);

  useEffect(() => {
    const fetchBuses = async () => {
      try {
        setLoading(true);
        const params = new URLSearchParams();
        if (searchInfo.departureCity) params.append("departureCity", searchInfo.departureCity);
        if (searchInfo.arrivalCity) params.append("arrivalCity", searchInfo.arrivalCity);

        const response = await axios.get<Bus[]>(`${API_BASE}/buses?${params.toString()}`);
        setBuses(response.data);
      } catch (error) {
        console.error("Failed to fetch buses", error);
      } finally {
        setLoading(false);
      }
    };

    fetchBuses();
  }, [searchInfo.departureCity, searchInfo.arrivalCity]);

  return (
    <section>
      <div className="mb-6 flex flex-wrap items-center justify-between gap-3">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">Available Buses</h2>
          <p className="text-sm text-slate-600">
            {searchInfo.departureCity || "All cities"} -> {searchInfo.arrivalCity || "All cities"}
            {searchInfo.date ? ` | ${searchInfo.date}` : ""}
          </p>
        </div>
        <Link to="/" className="rounded-lg border border-slate-300 px-4 py-2 text-sm font-semibold text-slate-700 hover:bg-slate-100">
          Modify Search
        </Link>
      </div>

      {loading ? <p className="text-slate-600">Loading buses...</p> : null}
      {!loading && buses.length === 0 ? (
        <div className="rounded-xl bg-white p-6 text-center text-slate-600 shadow-travel ring-1 ring-slate-200">
          No buses found for this route.
        </div>
      ) : null}

      <div className="grid gap-4 md:grid-cols-2">
        {buses.map((bus) => (
          <BusCard key={bus.id} bus={bus} />
        ))}
      </div>
    </section>
  );
};

export default BusList;
